// Reference Score Calculation
// Weights: components_breadth(20%), components_risk(10%), technical_rsi(15%), technical_atr(10%), technical_zscore(10%), technical_macd(5%), technical_divergence(5%), money_flow_futures(15%), money_flow_etf(10%)

const weights = {
    components_breadth: 0.20,
    components_risk: 0.10,
    technical_rsi: 0.15,
    technical_atr: 0.10,
    technical_zscore: 0.10,
    technical_macd: 0.05,
    technical_divergence: 0.05,
    money_flow_futures: 0.15,
    money_flow_etf: 0.10
};

// Default scores if no data (neutral = 50)
let componentsBreadthScore = 50;
let componentsRiskScore = 50;
let technicalRsiScore = 50;
let technicalAtrScore = 50;
let technicalZscoreScore = 50;
let technicalMacdScore = 50;
let technicalDivergenceScore = 50;
let moneyFlowFuturesScore = 50;
let moneyFlowEtfScore = 50;

if (msg.payload && msg.payload.length > 0) {
    const data = msg.payload[0];

    // Components: Breadth (percentage of stocks above moving average)
    if (data.components_breadth !== undefined) {
        componentsBreadthScore = Math.min(100, Math.max(0, data.components_breadth));
    }

    // Components: Risk score
    if (data.components_risk !== undefined) {
        componentsRiskScore = 100 - Math.min(100, Math.max(0, data.components_risk));
    }

    // Technical: RSI (30-70 neutral, above 70 = overbought, below 30 = oversold)
    if (data.rsi !== undefined) {
        if (data.rsi >= 70) technicalRsiScore = 100;
        else if (data.rsi <= 30) technicalRsiScore = 0;
        else technicalRsiScore = ((data.rsi - 30) / 40) * 100;
    }

    // Technical: ATR (normalize to 0-100, lower is better for trend)
    if (data.atr_percent !== undefined) {
        technicalAtrScore = Math.min(100, Math.max(0, 100 - (data.atr_percent * 10)));
    }

    // Technical: Z-Score (-2 to +2 normalized to 0-100)
    if (data.zscore !== undefined) {
        technicalZscoreScore = ((data.zscore + 2) / 4) * 100;
        technicalZscoreScore = Math.min(100, Math.max(0, technicalZscoreScore));
    }

    // Technical: MACD (positive histogram = bullish)
    if (data.macd_histogram !== undefined) {
        technicalMacdScore = data.macd_histogram > 0 ? 50 + (Math.min(50, data.macd_histogram * 100)) : 50 + (Math.max(-50, data.macd_histogram * 100));
    }

    // Technical: Divergence (price vs indicator)
    if (data.divergence !== undefined) {
        const divergenceScores = { bullish: 100, neutral: 50, bearish: 0 };
        technicalDivergenceScore = divergenceScores[data.divergence] || 50;
    }

    // Money Flow: Futures (NQ futures position change)
    if (data.futures_oi_change !== undefined) {
        moneyFlowFuturesScore = Math.min(100, Math.max(0, 50 + data.futures_oi_change * 10));
    }

    // Money Flow: ETF (TQQQ/QQQ inflow)
    if (data.etf_inflow !== undefined) {
        moneyFlowEtfScore = Math.min(100, Math.max(0, 50 + data.etf_inflow * 10));
    }
}

// Calculate final weighted score
const finalScore = Math.round(
    componentsBreadthScore * weights.components_breadth +
    componentsRiskScore * weights.components_risk +
    technicalRsiScore * weights.technical_rsi +
    technicalAtrScore * weights.technical_atr +
    technicalZscoreScore * weights.technical_zscore +
    technicalMacdScore * weights.technical_macd +
    technicalDivergenceScore * weights.technical_divergence +
    moneyFlowFuturesScore * weights.money_flow_futures +
    moneyFlowEtfScore * weights.money_flow_etf
);

msg.payload = {
    components_breadth_score: Math.round(componentsBreadthScore),
    components_risk_score: Math.round(componentsRiskScore),
    technical_rsi_score: Math.round(technicalRsiScore),
    technical_atr_score: Math.round(technicalAtrScore),
    technical_zscore_score: Math.round(technicalZscoreScore),
    technical_macd_score: Math.round(technicalMacdScore),
    technical_divergence_score: Math.round(technicalDivergenceScore),
    money_flow_futures_score: Math.round(moneyFlowFuturesScore),
    money_flow_etf_score: Math.round(moneyFlowEtfScore),
    final_reference_score: finalScore,
    timestamp: new Date()
};

return msg;
